import 'package:bookly/Core/Utils/Errors/failure.dart';import 'package:bookly/Core/network/dio.dart';import 'package:bookly/Features/Home/Data/Repos/home_repo.dart';import 'package:dartz/dartz.dart';import 'package:dio/dio.dart';import '../model/book_model.dart';class HomeRepoImpl implements HomeRepo {  @override  Future<Either<Failure, List<BookModel>>> fetchNewsBooksBooks() async {    try {      var data = await DioHelper.getAPIData(          path: 'volumes?Filtering=free-ebooks&Sorting=newest &q=computer science');      List<BookModel> books = [];      for (final item in data['items']) {        books.add(BookModel.fromJson(item));      }      return right(books);    } catch (e) {      if (e is DioException) {        return left(ServerFailure.fromDioError(e));      } else {        return left(ServerFailure.fromResponse(e, e.hashCode));      }    }  }  @override  Future<Either<Failure, List<BookModel>>> fetchFeaturedBooks() async {    try {      var data = await DioHelper.getAPIData(          path: 'volumes?Filtering=free-ebooks&q=subject:Programming');      List<BookModel> books = [];      for (final item in data['items']) {        books.add(BookModel.fromJson(item));      }      return right(books);    } catch (e) {      if (e is DioException) {        return left(ServerFailure.fromDioError(e));      } else {        return left(ServerFailure.fromResponse(e, e.hashCode));      }    }  }}